SELECT *
FROM work_schedules



        AND employee_id = #{employeeId}


        AND work_date = #{workDate}


        AND status = #{status}


ORDER BY work_date DESC, start_time DESC
LIMIT #{offset}, #{size}

SELECT *
FROM work_schedules
WHERE employee_id = #{employeeId}
  AND DATE_FORMAT(work_date, '%Y-%m') = #{month}
ORDER BY work_date ASC, start_time ASC
